const items = $input.all();
let htmlTable = `<table border="1" cellpadding="5" cellspacing="0" style="border-collapse: collapse; font-family: Arial, sans-serif; width: 100%;">
  <tr style="background-color: #f2f2f2;">
    <th>Sıra</th>
    <th>Hesap</th>
    <th>Kullanıcı</th>
    <th>Fatura Tarihi</th>
    <th>Ekstre Dönemi</th>
    <th>Fatura Dosyası</th>
    <th>Makbuz Dosyası</th>
    <th>İmza Sorumlusu</th>
    <th>Durum</th>
  </tr>`;

let successCount = 0;
let errorCount = 0;
const binData = {};
const attachmentKeys = [];

for (let i = 0; i < items.length; i++) {
  const item = items[i].json;

  let email = item.email || '';
  if (!email) email = `Hesap-${i+1}`;

  const owner = item.owner || '';
  const signatureText = item.signatureText || 'Belirtilmedi';
  const targetInvoice = item.targetInvoice || 'last';

  const isPrevious = targetInvoice === 'previous';
  const ekstreDonemi = isPrevious ? 'Geçen Ay' : 'Güncel';
  let faturaTarihi = '-';

  const statusHtml = item.status === 'success' ? 'Başarılı' : 'Hatalı';

  let invName = '-';
  let recName = '-';

  if (item.status === 'success') {
     successCount++;
     if (item.base64Files && item.base64Files.length > 0) {
       for (let j = 0; j < item.base64Files.length; j++) {
         const fileObj = item.base64Files[j];
         const key = `file_${i}_${j}`;
         binData[key] = {
           data: fileObj.content,
           mimeType: 'application/pdf',
           fileName: fileObj.filename
         };
         attachmentKeys.push(key);

         if (fileObj.filename.includes('fatura')) {
           invName = fileObj.filename;
           const dateRe = new RegExp('_fatura_(([0-9]{2})-([0-9]{2})-([0-9]{4}))[.]pdf', 'i');
           const dateMatch = invName.match(dateRe);
           if (dateMatch) {
             faturaTarihi = dateMatch[2] + '.' + dateMatch[3] + '.' + dateMatch[4];
           }
         }

         if (fileObj.filename.includes('makbuz')) recName = fileObj.filename;
       }
     }
     htmlTable += `<tr>
      <td>${i+1}</td>
      <td>${email}</td>
      <td>${owner}</td>
      <td>${faturaTarihi}</td>
      <td>${ekstreDonemi}</td>
      <td>${invName}</td>
      <td>${recName}</td>
      <td>${signatureText}</td>
      <td style="color: green; font-weight: bold;">${statusHtml}</td>
    </tr>`;
  } else {
     errorCount++;
     htmlTable += `<tr>
      <td>${i+1}</td>
      <td>${email}</td>
      <td>${owner}</td>
      <td>-</td>
      <td>${ekstreDonemi}</td>
      <td>-</td>
      <td>-</td>
      <td>${signatureText}</td>
      <td style="color: red; font-weight: bold;">${statusHtml} (${item.errorMessage || item.error || 'Bilinmeyen Hata'})</td>
    </tr>`;
  }
}
htmlTable += `</table>`;

// ==========================================
// Ay ve Tarih Hesaplamaları (Yukarı Taşıdık)
// ==========================================
const dTitle = new Date();
dTitle.setMonth(dTitle.getMonth() - 1);
const monthNames = ["Ocak", "Şubat", "Mart", "Nisan", "Mayıs", "Haziran", "Temmuz", "Ağustos", "Eylül", "Ekim", "Kasım", "Aralık"];
const previousMonthName = monthNames[dTitle.getMonth()];
const targetYear = dTitle.getFullYear();

// ==========================================
// HTML Şablonu (Dinamik Başlık ile Birlikte)
// ==========================================
const summaryHtml = `
  <div style="font-family: Arial, sans-serif; color: #333;">
    <h2>${previousMonthName} Ayı ChatGPT Fatura Özeti</h2>
    <p>Fatura indirme otomasyonu tamamlandı. İşlem detayları aşağıdadır:</p>
    <ul>
      <li><b>Toplam İşlem:</b> ${items.length}</li>
      <li><b style="color: green;">Başarılı:</b> ${successCount}</li>
      <li><b style="color: red;">Hatalı:</b> ${errorCount}</li>
    </ul>

    <p>Bu mesaj otomasyon servisinden otomatik olarak gönderilmiştir.<br>
    İndirilen fatura ve makbuzlar ekte yer almaktadır.</p>

    <br>
    ${htmlTable}
    <br>
  </div>
`;

const mailSubject = `${targetYear} ${previousMonthName} Ayı ChatGPT Faturaları`;
const fromEmail = `${targetYear} ${previousMonthName} Ayı ChatGPT Faturaları <fatihkilinc@tim.org.tr>`;

return [
  {
    json: {
      fromEmail,
      mailSubject,
      htmlBody: summaryHtml,
      attachmentsStr: attachmentKeys.join(',')
    },
    binary: binData
  }
];
